#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Structure for Trie node
typedef struct TrieNode {
    struct TrieNode* children[26];
    int isEndOfWord;
} TrieNode;

// Function to create a new Trie node
TrieNode* createNode() {
    TrieNode* newNode = (TrieNode*)malloc(sizeof(TrieNode));
    for (int i = 0; i < 26; i++) {
        newNode->children[i] = NULL;
    }
    newNode->isEndOfWord = 0;
    return newNode;
}

// Function to insert a substring into the Trie
void insert(TrieNode* root, char* str) {
    TrieNode* node = root;
    for (int i = 0; i < strlen(str); i++) {
        int index = str[i] - 'a';
        if (!node->children[index]) {
            node->children[index] = createNode();
        }
        node = node->children[index];
    }
    node->isEndOfWord = 1;
}

// Function to count distinct substrings using Trie
int countDistinctSubstrings(char* str) {
    TrieNode* root = createNode();
    int count = 0;
    for (int i = 0; i < strlen(str); i++) {
        char substr[100];
        for (int j = i; j < strlen(str); j++) {
            substr[j - i] = str[j];
            substr[j - i + 1] = '\0';
            insert(root, substr);
        }
    }
    return count + 1;
}

int main() {
    char str[100];
    scanf("%s", str);
    printf("%d\n", countDistinctSubstrings(str));
    return 0;
}

